    constructor() {
        this.label = '';
        this.hint = '';
        this.error = '';
        this.placeholder = '';
        this.value = '';
        this.rows = 4;
        this.required = false;
        this.disabled = false;
        this.id = '';
        this.name = '';
        this.maxLength = null;
        this.wrapperClass = '';
        this.valueChange = new EventEmitter();
        this.blur = new EventEmitter();
        this.autoId = `pf-textarea-${++nextUid}`;
    }
    get textareaId() {
        return this.id || this.autoId;
    }
    get hintId() {
        return this.hint && !this.error ? `${this.textareaId}-hint` : null;
    }
    get errorId() {
        return this.error ? `${this.textareaId}-error` : null;
    }
    get describedBy() {
        const ids = [this.hintId, this.errorId].filter(Boolean);
        return ids.length ? ids.join(' ') : null;
    }
    get fieldClasses() {
        return ['ori-field', this.wrapperClass].filter((c) => Boolean(c)).join(' ');
    }
    get labelClasses() {
        return ['ori-field__label', this.required ? 'ori-field__label--required' : null]
            .filter((c) => Boolean(c))
            .join(' ');
    }
    onInput(event) {
        const value = event.target.value;
        this.value = value;
        this.valueChange.emit(value);
    }
